{"type":"FlowTopic","triggers":[{"type":"Trigger","name":"c06921b7fb7e4af190b2572b91b16e55","triggerType":"request","applicability":{"type":"Applicability","mode":"script","value":"true"},"id":"c06921b7fb7e4af190b2572b91b16e55"}],"goals":[{"name":"primary","trigger_id":"c06921b7fb7e4af190b2572b91b16e55","nodes":[{"type":"StartGoal","goal_id":"primary","greeting_msg":{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:c66d503787876a5002fdeac73cbb3574:node:01e187c8fecc4e69b12b74223341cef7:field:GreetingMsg", vaContext.getRequesterLang())"},"id":"01e187c8fecc4e69b12b74223341cef7","name":"Start","expert_mode":false},{"type":"TerminateGoal","goal_id":"primary","confirmation_msg":{"type":"String","mode":"string","value":""},"id":"339ff2bbaf26411c99125e25bbb698cd","name":"End","expert_mode":false},{"type":"InputPrompt","variable_id":"fed1ead3a7194235b4565e7c96d3ea54","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Please enter the customer ID", vaContext.getRequesterLang())"},"default_value":{"type":"String","mode":"string","value":""},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"98a55eb3ca4f416c914596ea99ed709a","name":"Customer Input","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"script","value":"(function execute(inputs, outputs) {
 var customerGR = new GlideRecord('x_cpszo_spoke_customer_profile');
 if (customerGR.get('number', inputs.number)) {
 var riskBand = customerGR.getValue('risk_band');

 if (riskBand == 'low') {
 outputs.greeting = gs.getMessageLang("Welcome! Your profile looks great, {0}.", vaContext.getRequesterLang(), [inputs.number]);
 } else if (riskBand == 'medium') {
 outputs.greeting = gs.getMessageLang("Hi there! We’ll help you navigate your profile, {0}.", vaContext.getRequesterLang(), [inputs.number]);
 } else if (riskBand == 'high') {
 outputs.greeting = gs.getMessageLang("Hello! We’re here to support you with your high-risk profile, {0}.", vaContext.getRequesterLang(), [inputs.number]);
 } else {
 outputs.greeting = gs.getMessageLang("Hello! Let’s get started, {0}.", vaContext.getRequesterLang(), [inputs.number]);
 }
 } else {
 outputs.greeting = gs.getMessageLang("Hello! We couldn’t find your profile, but we’re here to help.", vaContext.getRequesterLang());
 }
})(inputs, outputs);"}],"request_feedback":true,"isCollapsible":true,"id":"4c6a094bd9ec4a07b7757089778172d1","name":"Bot Response","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"RecordOutputPrompt","mode":"query","table":"x_cpszo_spoke_offer_tracker","fields":["number","offer_type","installment_amount","delinquency_status"],"request_feedback":true,"id":"47fe11228a02430ba012ec60aa17188c","name":"Display Cards","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"reference_qualifier_condition":"number={{vaInputs.customer_input}}^ORnumberLIKE{{vaInputs.customer_input}}","condition":{"type":"Condition","mode":"glide_query","value":"number={{vaInputs.customer_input}}^ORnumberLIKE{{vaInputs.customer_input}}"}},{"type":"ChoiceInputPrompt","expression_mode":"simple","metadataScript":"","cardName":"","cardFields":[],"id":"1c9e34b578dc4806991e6a7319914041","name":"Offer Choice1","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"variable_id":"e3de050d6e104a89b6dd867367989d76","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Click on the offer card above for accepting the offer.", vaContext.getRequesterLang())"},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"description":""},{"type":"RecordOutputPrompt","mode":"query","table":"x_cpszo_spoke_offer_tracker","fields":["number","acceptance_date","offer_status"],"request_feedback":true,"id":"35645cf0590a45cdb10d7eb8dca657f5","name":"Offer Status","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"reference_qualifier_cond